mapper.select:
select id, phone, scene, code, expires_at, used_at, error_count, created_at, updated_at
from cook_verification_codes
where phone = #{phone}
  and scene = #{scene}
order by created_at desc
limit 1

mapper.update:
update cook_verification_codes
set used_at = current_timestamp,
    updated_at = current_timestamp
where phone = #{phone}
  and scene = #{scene}
  and used_at is null
